// Parse Slack slash command payload
const body = $input.first().json;
const text = (body.text || '').trim();
const parts = text.split(/\s+/);
const subcommand = parts[0] || '';

// Route: /ppm-retry <event-id>
// Route: /ppm-resolve [plane|odoo|manual] <link-id>
// Route: /ppm-status

return [{
  json: {
    subcommand: subcommand,
    args: parts.slice(1),
    user_id: body.user_id,
    channel_id: body.channel_id,
    response_url: body.response_url,
    raw_text: text
  }
}];

// /ppm-retry <event-id>
const eventId = $json.args[0];
if (!eventId) {
  return [{ json: { response_type: 'ephemeral', text: 'Usage: /ppm-retry <event-id>' } }];
}

// TODO: Look up event, re-execute sync
return [{ json: {
  response_type: 'in_channel',
  text: `:arrows_counterclockwise: Retrying sync for event \`${eventId}\`...`
} }];

// /ppm-resolve [plane|odoo|manual] <link-id>
const strategy = $json.args[0];
const linkId = $json.args[1];

if (!strategy || !linkId || !['plane', 'odoo', 'manual'].includes(strategy)) {
  return [{ json: { response_type: 'ephemeral', text: 'Usage: /ppm-resolve [plane|odoo|manual] <link-id>' } }];
}

// TODO: Apply resolution strategy
return [{ json: {
  response_type: 'in_channel',
  text: `:white_check_mark: Conflict \`${linkId}\` resolved using **${strategy}** strategy.`
} }];

// /ppm-status — show sync health dashboard
// TODO: Query Supabase for live stats
return [{ json: {
  response_type: 'ephemeral',
  text: ':bar_chart: *PPM Clarity Status*\n- Active links: _querying..._\n- Sync state: :white_check_mark: Healthy\n- Last reconciliation: 2 AM today\n- Conflicts pending: 0'
} }];
